import org.springframework.kafka.annotation.KafkaListener;
import org.springframework.kafka.core.DefaultKafkaConsumerFactory;
import org.springframework.kafka.listener.SeekToCurrentBatchErrorHandler;
import org.springframework.stereotype.Service;

@Service
public class OrderProcessor {

    @Autowired
    private DefaultKafkaConsumerFactory<String, Object> consumerFactory;

    @KafkaListener(topics = "order_events", groupId = "order-group")
    public void processOrder(OrderCreatedEvent event) {
        try {
            // Process the order creation event
            System.out.println("Processing order: " + event.getOrderId());
            updateInventory(event);
            commitOffset();
        } catch (Exception e) {
            handleFailure(e);
        }
    }

    private void updateInventory(OrderCreatedEvent event) {
        // Logic to reserve stock in inventory service
    }

    private void commitOffset() {
        consumerFactory.getContainerProperties().getBatchErrorHandler().handle(new SeekToCurrentBatchErrorHandler());
    }

    private void handleFailure(Exception e) {
        System.err.println("Failed to process order: " + e.getMessage());

        if (consumerFactory.getContainerProperties().getMaxAttempts() > 0 && 
            consumerFactory.getContainerProperties().getAttemptNumber() < consumerFactory.getContainerProperties().getMaxAttempts()) {
            // Retry logic
            return;
        }

        // Move message to DLQ
        moveToDLQ(event);
    }

    private void moveToDLQ(OrderCreatedEvent event) {
        try (KafkaTemplate<String, Object> dlqProducer = new KafkaTemplate<>(consumerFactory)) {
            dlqProducer.send("order_events_dlq", event.getOrderId(), event);
        } catch (Exception ex) {
            System.err.println("Failed to move message to DLQ: " + ex.getMessage());
        }
    }
}
