```java
@Service
public class OrderSaga {

    private final KafkaTemplate<String, Object> kafkaTemplate;
    private final String topic = "order_events";
    private final SchemaRegistryUtil schemaRegistryUtil;

    @Autowired
    public OrderSaga(KafkaTemplate<String, Object> kafkaTemplate, SchemaRegistryUtil schemaRegistryUtil) {
        this.kafkaTemplate = kafkaTemplate;
        this.schemaRegistryUtil = schemaRegistryUtil;
    }

    public void createOrder(Order order) throws Exception {
        // Step 1: Create the order in the Order Service
        OrderService orderService = new OrderServiceImpl();
        orderService.createOrder(order);

        // Step 2: Reserve stock in the Inventory Service
        InventoryService inventoryService = new InventoryServiceImpl();
        inventoryService.reserveStock(order.getOrderId(), order.getItems());

        // Send a success message to Kafka
        kafkaTemplate.send(topic, "order_created", order);
    }

    public void cancelOrder(String orderId) throws Exception {
        // Compensating action: Cancel the order in the Order Service
        OrderService orderService = new OrderServiceImpl();
        orderService.cancelOrder(orderId);

        // Compensating action: Release reserved stock in the Inventory Service
        InventoryService inventoryService = new InventoryServiceImpl();
        inventoryService.releaseStock(orderId);

        // Emit a compensation event to Kafka
        emitCompensationEvent("ORDER_CANCELLED", orderId, "Failed to reserve stock");
    }

    private void emitCompensationEvent(String eventType, String orderId, String reason) throws Exception {
        // Serialize the order cancellation event to Avro format
        String avroSchemaString = OrderCancelledEvent.getClassSchema().toString();
        String subject = "order_events-value";

        // Register the schema with the Schema Registry
        schemaRegistryUtil.registerSchema(subject, avroSchemaString);

        // Send the compensation event to Kafka topic
        kafkaTemplate.send(new ProducerRecord<>(topic, orderId, new OrderCancelledEvent(eventType, orderId, reason)));
    }
}
