import org.apache.flink.api.common.functions.MapFunction;
import org.apache.flink.streaming.api.datastream.DataStream;
import org.apache.flink.streaming.api.environment.StreamExecutionEnvironment;
import org.apache.flink.streaming.connectors.kafka.FlinkKafkaConsumer;
import io.confluent.kafka.schemaregistry.client.CachedSchemaRegistryClient;

public class OrderProcessingJob {

    public static void main(String[] args) throws Exception {
        final StreamExecutionEnvironment env = StreamExecutionEnvironment.getExecutionEnvironment();

        // Configure the restart strategy
        env.getConfig().setRestartStrategy(RestartStrategies.fixedDelayRestart(3, Time.seconds(10)));

        // Kafka consumer configuration
        Properties kafkaProps = new Properties();
        kafkaProps.put("bootstrap.servers", "localhost:9092");
        kafkaProps.put("group.id", "order-group");
        kafkaProps.put("key.deserializer", "org.apache.kafka.common.serialization.StringDeserializer");
        kafkaProps.put("value.deserializer", KafkaAvroDeserializer.class.getName());
        kafkaProps.put("schema.registry.url", "http://localhost:8081");

        FlinkKafkaConsumer<String> consumer = new FlinkKafkaConsumer<>("order_events", new MyOrderEventDeserializationSchema(), kafkaProps);

        DataStream<OrderCreatedEvent> orderEvents = env.addSource(consumer)
                .map(new MapFunction<String, OrderCreatedEvent>() {
                    @Override
                    public OrderCreatedEvent map(String value) throws Exception {
                        // Deserialize the event and return it
                        return deserializeOrderEvent(value);
                    }
                })
                .filter(event -> processOrder(event))
                .name("Process Orders");

        DataStream<OrderCreatedEvent> failedEvents = orderEvents.filter(event -> !processOrder(event))
                .map(new MapFunction<OrderCreatedEvent, OrderCreatedEvent>() {
                    @Override
                    public OrderCreatedEvent map(OrderCreatedEvent event) throws Exception {
                        // Log the failure and move to DLQ
                        System.err.println("Failed to process order: " + event.getOrderId());
                        return event;
                    }
                })
                .name("Move Failed Orders to DLQ");

        failedEvents.addSink(new FlinkKafkaProducer<>("order_events_dlq", new MyOrderEventDeserializationSchema(), kafkaProps))
                .name("Send Failed Events to DLQ");

        env.execute("Order Processing Job");
    }

